var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"천장이 무너지다니 하마터면 큰일날 뻔했네요.","JPN":"天井が崩れるなんて、危ないところでしたね。","ENG":"The ceiling collapsed? That was a close one.","TWN":"天花板竟然塌了，差點出大事。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"어디 다친 데는 없으셨어요? 좋은 연고를 만드는 비법을 알아 왔답니다.","JPN":"お怪我はありませんか？　よく効く塗り薬を作る秘訣を調べてきました。","ENG":"Are you hurt anywhere? We learned how to make an excellent healing ointment.","TWN":"你沒受傷吧？聽説有找到製作藥膏的方法。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"걱정 마세요, 에델. 저도 카운터랍니다. 머리에 혹이 난 정도예요.","JPN":"心配いりませんわ、エデル。私もカウンターですから。頭にたんこぶができた程度です。","ENG":"No need, Edel. I am also a Counter. It is just a minor bump on the head.","TWN":"別擔心，艾瑟兒。我也是制裁者。不過就是頭上有個包而已。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그 정도로 끝나서 다행이에요.","JPN":"その程度で済んで幸いでした。","ENG":"Thank goodness it only ended at that.","TWN":"幸好傷得不重。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그래도 밤에 편히 주무실 수 있겠네요. 벽 속에서 들리던 소음의 원인이 사라졌으니까요.","JPN":"ですが、これで夜ぐっすりお休みになれますね。壁の中から聞こえていた騒音のもとが消えたのですから。","ENG":"But at least you'll be able to sleep soundly now. The cause of the noises within the walls is gone now.","TWN":"不過晚上你總算可以睡個好覺了。因為已經解決掉了在牆裡雜音的來源。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님도 자주 쥐덫을 사다 놓으셨잖아요?","JPN":"レジーナ様もよくネズミ取りを用意されてたじゃないですか。","ENG":"You used to buy and lay out mouse traps, didn't you?","TWN":"蕾佳娜不是也經常買捕鼠器嘛？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저도 그러길 바라지만…… 한동안 꿈자리가 사나울 것 같아요.","JPN":"私もそうであってほしいですけど……しばらくは夢見が悪そうですわ。","ENG":"I wish that were true, but... I believe my dreams will not be so pleasant for a while now.","TWN":"希望如此吧……不過我總感覺會做很長時間的噩夢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"수로에서 오래된 유품들을 찾았습니다. 선조들이 영지를 다스리던 시절에 갇힌 사람들이었겠죠.","JPN":"水路で古い遺品を見つけました。ご先祖様が領地を治めていた頃に閉じ込められた人々だったのでしょう。","ENG":"We found old relics in the waterway. They are from the people who were trapped down there generations ago.","TWN":"我在水道裡找到了古老的遺物。應該都是先祖們統治領地時期囚禁的人吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그러게요. 정말 안타까운 일이에요.","JPN":"そうですね。実に残念なお話です。","ENG":"Yes... It is a shame indeed.","TWN":"是啊，我也對此深表遺憾。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"두 분과 마주친 잔해들은 오래 전에 돌아가신 분들의 유골에서 희귀한 지식을 포식했을 텐데요.","JPN":"お二人が戦った残骸は昔亡くなった方々の遺骨から貴重な知識を捕食したはずです。","ENG":"The Remains you both encountered over there must feast on some rare knowledge from those old relics.","TWN":"兩位遇到的殘骸，應該從很久以前去世的人們的遺骨中享用到珍貴的知識吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그런 진미를 맛도 못 보고 떠나보내다니…….","JPN":"そんな珍味を、味わうこともなく倒してしまうなんて……","ENG":"What a pity that we couldn't taste them...","TWN":"只可惜我都還沒嚐到就……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"참, 다른 분들 앞에서 입맛을 다시는 건 숙녀답지 못한 행위였죠.","JPN":"まあ、他の方々の前で舌なめずりをするのは淑女らしくない行為でしたね。","ENG":"Oh! How unladylike of us to be smacking our lips in front of others.","TWN":"哎呀，在大家面前表現出嘴饞的樣子可不是淑女所為。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"……에델, 제 얘기는 애도를 표하자는 의미였어요.","JPN":"……エデル、私の話は哀悼しようという意味でしたのよ。","ENG":"...Edel, what I meant was that we show our condolences.","TWN":"……艾瑟兒，我的意思是讓你表示哀悼。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아하하, 나 보면서 다시지만 마. 보통 사람은 트라우마 걸린다구.","JPN":"あはは、アタシを見ながらはやらないでね。普通の人間はトラウマになっちゃうよ。","ENG":"Ahaha! Just don't look at me while you're doing it. But for normal people, they'll be traumatized.","TWN":"哈哈哈，不要看著我擦口水，要是換作一般人肯定會嚇壞。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그보다 레지나, 감기 기운은 좀 어때?","JPN":"それよりレジーナ、風邪の具合はどう？","ENG":"But enough about that. What about you, Regina? How are you feeling?","TWN":"對了，蕾佳娜，你感冒好點了嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"기침은 많이 잦아들었어요. 그 아이가 준 열매가 몸에 잘 맞나 봐요.","JPN":"咳はだいぶ収まりましたわ。あの子がくれた木の実がよく効いたみたいです。","ENG":"The coughs lessened. I think those fruits that girl gave me are helping.","TWN":"咳嗽舒緩很多。那孩子給的果實好像很管用。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그럼 오늘은 이만 쉬시는 편이 어떨까요? 무리하면 더 심해질 수도 있답니다.","JPN":"それでは今日はもうお休みになってはいかがですか？　無理するともっとひどくなるかもしれません。","ENG":"You should rest for the rest of the day. It might get worse if you stress yourself out too much.","TWN":"那今天就休息一下吧？硬撐的話，感冒可能會變得更嚴重。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨. 지금 읽고 있는 서신들은 오늘 중으로 답장을 보내야 해요.","JPN":"いいえ。今読んでいる手紙は今日中に返事をしないといけませんので。","ENG":"I cannot. I have to write a response to all the messages I am reading by today.","TWN":"不行。我現在看的這些信，今天之內都得寫好回信。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"들어 보세요. 아무리 합법적인 영역에서 활동하라고 해도 이 모양이라고요.","JPN":"聞いてください。いくら合法的な領域で活動するように話してもこの様です。","ENG":"Look at this. Even if we are operating under the law, nothing has really changed.","TWN":"你看，就算我說讓他們在合法的領域活動，也還是這個樣子。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>밀반입된 아티팩트를 확보했고, 관계자들을 입막음하는 과정에서 그 효과를 입증하는 데 성공했습니다.</color>","JPN":"<color=#ffd34c>密輸されたアーティファクトを確保し、関係者の口止めをする過程においてその効果を立証することに成功しました。</color>","ENG":"<color=#ffd34c>Secured the smuggled Artifact. Proved its effectiveness while trying to forbid the related party to speak.</color>","TWN":"<color=#ffd34c>我們拿到了走私的人造神器，在讓相關人員閉嘴的過程中，順便證明了它的功效。</color>"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>존경하는 부학회장님, 인신 공양은 저희 학부 연구에 필수적인 과정입니다. 부디 허가해 주시길 바랍니다.</color>","JPN":"<color=#ffd34c>親愛なる副学会長様、人身御供は我々学部の研究に必須の過程です。どうか許可をお願いいたします。</color>","ENG":"<color=#ffd34c>Dear Vice President. Human sacrifice is a necessary procedure to our research. Please allow us to proceed.</color>","TWN":"<color=#ffd34c>尊敬的副學會長，活人祭祀是我們學院研究的必需過程。懇請你同意。</color>"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>신생 도시국가의 정부 장악은 매우 순조롭습니다. 반발하는 소수의 인사들을 축출할 필요가 있으니 헤아려 주십시오.</color>","JPN":"<color=#ffd34c>新生都市国家の政府掌握はとても順調です。反発する少数派を追い出す必要があるので、ご考慮願います。</color>","ENG":"<color=#ffd34c>The overtake of the new city-state's government is going as planned. Please note that it will be necessary to oust the minority rebels in the area.</color>","TWN":"<color=#ffd34c>掌控新興城邦政府的過程很順利。不過我們需要驅逐少數反對人士，懇請你諒解。</color>"},"stage":{"bg":"DOCUMENTS","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L30_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"모두들 무척 잘해 주고 계시네요.","JPN":"みんな、とてもよくやってくれていますね。","ENG":"Everyone seems to be doing a good job.","TWN":"大家都做得很好啊。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아뇨! 이 많은 서신 중에 상식적인 내용이 하나도 없어요! 이래서야 그냥 악의 소굴이잖아!","JPN":"いいえ！　このたくさんの手紙の中に常識的な内容は一つもありません！　これではただの悪の巣窟ではないですか！","ENG":"No! Out of all these messages, not one of them contains any common sense! Judging by this, all we are is evil!","TWN":"不！這麼多的書信中，就沒有一條正常的內容！這樣的話，我們這裡不就成了罪惡的巢穴嘛！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"또 히스테리 시작이네. 매번 그렇게 방방 뛰기도 피곤하겠다.","JPN":"またヒステリーが始まったよ。毎回そんなに騒いで疲れないの？","ENG":"Ugh, there she goes with her hysteria again. It must be exhausting being you.","TWN":"又開始歇斯底里了。每次都這樣跳腳，活得多累啊。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"화병에 좋은 음식은 서늘한 성질이 있는 녹두라고 해요. 다음 출장 때 공수해 올까요?","JPN":"ヒステリーに効く食べ物は冷たい性質を持つ緑豆だそうですよ。次の出張で空輸してきましょうか？","ENG":"They say mung beans are highly effective in cooling one's temper. Should we procure some on our next business trip?","TWN":"聽說上火時多吃涼性的綠豆比較好。下次出差時，我們要不要空運一些過來？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하아…… 하소연할 상대가 없어…….","JPN":"はあ……常識人がいないわ……","ENG":"*Sigh...* There is no one here I can vent to...","TWN":"唉……真是連個能傾訴的人都沒有……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"어차피 학회는 비정상들만 모인 곳 아니야?","JPN":"どうせ学会は常識的じゃない人ばかりが集まるところでしょ？","ENG":"Isn't the Society a gathering of freaks?","TWN":"反正學會本來就是非正常人聚集的地方吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"어쩔 수 없지. 그 사람들에게는 레지나가 말하는 <color=#ffd34c>상식</color>이 비상식일 테니까.","JPN":"仕方ないじゃん。その人たちにとってはレジーナが言う<color=#ffd34c>常識</color>が非常識なんだからさ。","ENG":"What can you do? To them, the <color=#ffd34c>common sense</color> you talk about, Regina, is the absurd.","TWN":"沒辦法。對於那些人來說，蕾佳娜口中的<color=#ffd34c>常識</color>，應該算是違背常識才對。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"방법을 바꾸지 그래? 침식체에 따라 대처를 다르게 하는 것처럼 말이야.","JPN":"方法を変えたら？　侵食体によって対処のし方を変えるみたいにさ。","ENG":"So why don't you change your approach? You know, how you would deal with C.O.s differently depending on the type.","TWN":"不然乾脆換個方法吧？就像對付不同的侵蝕體，要用不同的方法一樣。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하루에 한 명은 너무 많으니까 이틀에 한 명만 죽이라고 타이르란 건가요?","JPN":"一日一人殺すのは多すぎるから、二日に一人にするように言い聞かせろとでも？","ENG":"Are you saying that I should tell them that killing one a day is too much so they should only kill one every two days?","TWN":"每天殺一個人太多了，所以勸他們每隔兩天殺一個嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"오우, 안 되지. 그랬다간 세상이 두 배로 따분해지잖아.","JPN":"うわ、ダメだよ。そしたら世の中が今よりも倍つまんなくなるよ。","ENG":"Oof, no. That'll just double the boredom in this world.","TWN":"噢噢，那可不行。那樣的話世界會變得雙倍無聊。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네, 그러시겠죠. 하나도 안 친절한 리벳 선생님.","JPN":"ええ、そうでしょうとも。まったく親切でないリベット先生。","ENG":"Yes. Whatever you say, not-so-kindhearted Ms. Rivet.","TWN":"是啊，應該是吧。一點都不親切的里維老師。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델, 내일 저 대신 영지를 시찰할 수 있을까요?","JPN":"エデル、明日は私の代わりに領地の視察に行ってもらえますか？","ENG":"Edel, could you be a dear and patrol around the estate for me tomorrow?","TWN":"艾瑟兒，明天你能替我視察領地嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"죄송해요, 레지나 님. 내일부터 다시 출장이랍니다.","JPN":"申し訳ありません、レジーナ様。明日からまた出張なんです。","ENG":"We're sorry, Miss Regina. But we leave for our business trip tomorrow.","TWN":"對不起，蕾佳娜。明天開始我們又要去出差。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"요즘 너무 외출이 잦은 것 아니에요? 저 몰래 이것저것 먹고 다니는 건 아니죠?","JPN":"最近外出が多すぎませんか？　私に内緒であれこれ食べ回っているのではないでしょうね？","ENG":"Do you not think your trips are getting too frequent? You are not feasting behind my back, are you?","TWN":"你最近外出得太頻繁了吧？該不是背著我到處亂吃東西吧？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"후후, 설마요. 이색적인 풍미를 발견하면 늘 레지나 님께 갖다 드리는 걸요.","JPN":"ふふ、まさか。異色の風味を発見したらいつもレジーナ様にお持ちしていますもの。","ENG":"Hah hah. Of course not. You know how we always bring it to you first whenever we find something exotic.","TWN":"呵呵，怎麼可能。每次發現有特色的風味，我們都會拿給蕾佳娜。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희는 레지나 님을 위해서 다 함께 힘내고 있어요.","JPN":"我々はレジーナ様のためにみんなで頑張っているのです。","ENG":"We are all doing our best for you, Miss Regina.","TWN":"我們正為了蕾佳娜一起努力。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그러고 보니 저희가 선물해 드린 예복은 언제쯤 입어 주실까요? 다들 기대하고 있답니다.","JPN":"そういえば我々がプレゼントした礼服はいつ着てくださいますか？　みんな楽しみにしているんです。","ENG":"Come to think of it, when will you be wearing the dress we bought you? We're all eager to see you in it.","TWN":"話說回來，我們送的禮服，你要什麼時候穿上呢？大家都很期待。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"죽기 전까진 안 입겠네요, 그 옷. 귀신 들린 드레스를 수선한 거라면서요.","JPN":"死ぬ間際までは着ないつもりですわ、その服。幽霊が憑りついたドレスをお直ししたものなのでしょう？","ENG":"Over my dead body. I heard that dress was originally possessed by a ghost.","TWN":"那件衣服，在我死之前應該都不會穿。不是說禮服上附著鬼魂嗎。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아아, 그럴 수가……. 레지나 님께 도움이 될 거라고 생각해서 어렵게 구했건만…….","JPN":"ああ、そんな……レジーナ様のお役に立てると思って苦労して手に入れたものですのに……","ENG":"Oh... What a shame... We put in so much effort to find it thinking it will help you...","TWN":"啊啊，怎麼可能……我們覺得那件衣服會對蕾佳娜有幫助，好不容易才買到的……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"오오. 흥미진진. 배우자의 외도를 의심하는 부부들 같은 대화야.","JPN":"おお。興味津々。パートナーの浮気を疑う夫婦の会話みたいだね。","ENG":"Ooh... Interesting... It's like watching a married couple fight over a suspicion of cheating.","TWN":"噢噢，真有趣，聽著好像懷疑對方有外遇的夫妻對話。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"서로 화해할 수 있게 오늘 밤엔 침대를 비워 줄까?","JPN":"仲直りできるように、今夜はベッドを空けてあげようか？","ENG":"If you two are going to make up later, do you want me to leave so you have the bed all to yourselves?","TWN":"今晚要不要我把床騰出來，讓你們倆和好？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"이크, 잉크병을 던지면 어떡해. 레지나.","JPN":"おっと、インク瓶投げないでよ。レジーナ。","ENG":"Whoa! It's dangerous throwing the ink bottle, Regina.","TWN":"哎呀，你怎麼可以扔墨水瓶，蕾佳娜。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"하마터면 내 이마에 맞을 뻔─","JPN":"おでこに当たるところだったじゃ……","ENG":"You almost hit me in the foreh–","TWN":"差點砸到我的額頭——"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"으윽, 분하다! 액자는 예상 못했는데!","JPN":"ううっ、悔しい！　写真立ては予想外だった！","ENG":"Urrgh...! Darn it! I didn't expect you to throw the picture frame too!","TWN":"呃啊，氣死我了！沒想到還有相框！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"쓸데없는 소리 그만하고 당장 나가요!","JPN":"余計なこと言ってないで、今すぐ出ていきなさい！","ENG":"I have had enough of your joking! Get out!","TWN":"別廢話啦，馬上給我出去！"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"흠흠. 이제야 좀 조용해졌네요.","JPN":"おっほん。やっと静かになりましたわ。","ENG":"Ahem... Finally, some peace.","TWN":"嗯嗯，這下總算安靜了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"집무로 바쁜 와중에도 홍차의 맛과 향을 즐기는 여유…….","JPN":"執務で追われる中でも紅茶の味と香りを楽しむ余裕……","ENG":"No matter how busy I am, I still have time to enjoy a cup of tea...","TWN":"在忙碌的工作中，還能享受紅茶的味道和香氣……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"으으, 역시 끔찍하게 쓰고 떫어.","JPN":"うう、やはりひどく苦いし渋いですわ。","ENG":"Yuk... It is still as bitter as ever.","TWN":"呃呃，果然苦澀得厲害。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"팬드래건 양은 이걸 무슨 맛으로 먹는담. 귀족들이라고 미각까지 별나진 않을 텐데.","JPN":"ペンドラゴンさんはこれのどこがお好きなのかしら。貴族だからといって味覚まで特別ではないはずですのに。","ENG":"How does Elizabeth drink this? I assume that nobles have the same taste buds as I do, no?","TWN":"潘德拉貢為什麼喜歡喝這個呢。就算是貴族，味覺應該也和別人一樣才對吧。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"최악이야. 일은 일대로 안 풀리지, 말이 통하는 사람도 없지…….","JPN":"最悪ですわ。仕事ははかどらないわ、話が通じる相手はいないわ……","ENG":"This is just the worst. Things are not working out as I planned, and there is no one I can talk to...","TWN":"真是糟透了。工作遇到這麼多麻煩，連個能傾訴的人也沒有……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"몸도…… 나른해서…… 감기 기운이 아직 안 떨어졌나……?","JPN":"体も……だるくて……風邪がまだ治っていないのかしら……？","ENG":"And I... I feel so tired... Is my cold coming back...?","TWN":"身體……也很疲憊……是感冒還沒好嗎……？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하으으……. 추워……. 정말 리벳 말처럼 과로 탓이려나…….","JPN":"はうう……寒い……本当にリベットの言うように過労のせい……？","ENG":"Uggghh... So cold... Perhaps Rivet was right about my overworking...","TWN":"哈啊……好冷……果真像里維說的那樣，是過勞嗎……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"역시 며칠 정도……. 쉬는 편이…….","JPN":"やはり何日か……休んだ方が……","ENG":"Maybe I should... rest for a... couple of days...","TWN":"果然還是……休息幾天比較……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"레지나 님? 레지나 님?","JPN":"レジーナ様？　レジーナ様？","ENG":"Miss Regina? Miss Regina?","TWN":"蕾佳娜？蕾佳娜？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저런. 책상에서 엎드려 주무시면 안 되죠. 몸도 편찮으신데.","JPN":"まあ。机でうつ伏せになってお休みになってはいけません。お体の具合もよくないのに。","ENG":"Oh my. You shouldn't be sleeping at your desk like this. You'll get even sicker.","TWN":"唉，趴在桌子上睡可不行。你本來就不舒服。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"자, 담요를 덮어 드렸으니 이제 따듯하실 거예요. 아무 걱정 말고 푹 쉬세요, 레지나 님.","JPN":"はい、ブランケットをお掛けしましたからすぐに暖かくなりますよ。何もご心配なさらずよくお休みくださいね、レジーナ様。","ENG":"Here. You'll now at least be warm with that blanket. Don't worry and sleep tight, Miss Regina.","TWN":"好了，我們給你蓋上毯子，這下就該暖和了。什麼都不要擔心，好好休息吧，蕾佳娜。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"앞으로는…… 아무것도 걱정할 필요 없을 테니까요.","JPN":"これからは……何の心配も必要なくなるでしょうから。","ENG":"From this day forward... You won't have to worry about anything.","TWN":"因為……以後你什麼都不需要再擔心了。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};